// Output: sessions_by_id keyed by session_id
// Each session has: start_ts, end_ts, message_count, transcript (NO timestamps inside)

const rows = $input.all().map(i => i.json);

const toMs = (ts) => {
  const d = new Date(ts);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : 0;
};

// Group by session_id
const sessions = new Map();
for (const r of rows) {
  const sid = String(r.session_id); // assumes session_id exists (you fixed the SQL)
  if (!sessions.has(sid)) sessions.set(sid, []);
  sessions.get(sid).push(r);
}

// Sort messages in each session by ts
for (const [sid, msgs] of sessions.entries()) {
  msgs.sort((a, b) => toMs(a.ts) - toMs(b.ts));
}

// Build output
const sessionsById = {};

const fmtLine = (m) => {
  const role = m.role || "unknown";
  const text = String(m.text || "").replace(/\s+/g, " ").trim();
  return `${role}: ${text}`;
};

for (const [sid, msgs] of sessions.entries()) {
  const startTs = msgs[0]?.ts ?? null;
  const endTs = msgs[msgs.length - 1]?.ts ?? null;

  sessionsById[sid] = {
    session_id: sid,
    message_count: msgs.length,
    start_ts: startTs,
    end_ts: endTs,
    transcript: msgs.map(fmtLine).join(" "),
  };
}

return [
  {
    json: {
      sessions_by_id: JSON.stringify(sessionsById),
    },
  },
];

