// Build grouped payload for Profile LLM.
// Supports BOTH input shapes:
// A) one item: { insights: [ {topic, insight_key, insight, strength, priority}, ... ] }
// B) many items: each item is an insight row {topic, insight_key, insight, strength, priority}

const items = $input.all().map(i => i.json);

// 1) Normalize to a flat array of insight rows
let insightRows = [];

// Case A: single object with an "insights" array
if (items.length === 1 && Array.isArray(items[0].insights)) {
  insightRows = items[0].insights;
} else {
  // Case B: items are already rows (or contain nested arrays)
  insightRows = items.flatMap(x => Array.isArray(x.insights) ? x.insights : [x]);
}

// 2) Group by topic
const byTopic = {};
for (const r of insightRows) {
  const topic = r.topic ?? "other";
  if (!byTopic[topic]) byTopic[topic] = [];

  byTopic[topic].push({
    insight_key: r.insight_key,
    insight: r.insight,
    strength: r.strength,
    priority: r.priority,
  });
}

// 3) Convert to array format
const payload = Object.entries(byTopic).map(([topic, insights]) => ({
  topic,
  insights,
}));

return [
  {
    json: {
      gold_by_topic: JSON.stringify(payload, null, 2).replace(/\n/g, ' ')
        .replace(/\s+/g, ' ')
        .trim(),

    },
  },
];
